class Solution {
    public String minWindow(String s, String t) {
        if (s.length() == 0 || t.length() == 0) return "";

        int[] countT = new int[128];
        for (char c : t.toCharArray()) countT[c]++;

        int required = t.length();
        int l = 0, r = 0;
        int minLen = Integer.MAX_VALUE;
        String minWindow = "";

        while (r < s.length()) {
            char c = s.charAt(r);
            if (countT[c] > 0) required--;
            countT[c]--;

            while (required == 0) {
                if (r - l + 1 < minLen) {
                    minLen = r - l + 1;
                    minWindow = s.substring(l, r + 1);
                }

                char cl = s.charAt(l);
                countT[cl]++;
                if (countT[cl] > 0) required++;
                l++;
            }
            r++;
        }

        return minWindow;
    }
}
